module comparator_64bit(  
    input [63:0] obf_A,  
    input [63:0] B,  
    output reg [2:0] result  
);  
    always @* begin  
        if (obf_A < B)  
            result = 3'b001;  
        else if (obf_A == B)  
            result = 3'b010;  
        else  
            result = 3'b100;  
    end  
endmodule
